import { Request } from 'aether'; // Assuming 'aether' provides a generic Request type
import { requireUser } from 'auth/module'; // Using path alias for cross-module import
import { parseParams } from 'lib/validate';
import { query } from 'lib/db';
import { ok, err } from 'lib/result';
import { TaskHistoryEntry } from 'modules/tasks/module.contract'; // Import the type from its own module contract

interface GetTaskHistoryParams {
  taskId: string;
}

export default async function getTaskHistory(req: Request): Promise<Response> {
  // Auth is always explicit: Every authenticated route must call requireUser(req) as its first statement.
  const authResult = await requireUser(req);
  if (authResult.isErr()) {
    return new Response(JSON.stringify({ error: authResult.error.message }), { status: authResult.error.status });
  }
  const user = authResult.value; // User is available if auth is successful

  // Validate request parameters
  const paramsResult = parseParams<GetTaskHistoryParams>(req, {
    taskId: 'string',
  });

  if (paramsResult.isErr()) {
    return new Response(JSON.stringify({ error: paramsResult.error.message }), { status: 400 });
  }
  const { taskId } = paramsResult.value;

  // Fetch task history from the database
  // No ORM: Raw SQL via /lib/db.ts
  const dbResult = await query<TaskHistoryEntry>(
    `SELECT
       id,
       task_id,
       event_type,
       old_value,
       new_value,
       user_id,
       created_at
     FROM audit_logs
     WHERE task_id = $1
     ORDER BY created_at DESC;`,
    [taskId]
  );

  if (dbResult.isErr()) {
    // Result type for errors: Do NOT throw exceptions for business logic errors.
    // Exceptions are only for unrecoverable system errors (e.g. DB connection failure).
    console.error('Database error fetching task history:', dbResult.error);
    return new Response(JSON.stringify({ error: 'Failed to retrieve task history.' }), { status: 500 });
  }

  const history = dbResult.value;

  if (history.length === 0) {
    // Optionally, return 404 if the task itself doesn't exist or has no history
    // For now, an empty array is a valid response if no history is found.
    // If we wanted to check if the task exists first, we'd need another query.
    // Assuming an empty array is acceptable for "no history found".
  }

  // Route handlers must return a typed Response
  return new Response(JSON.stringify(ok(history).value), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}
